import { EventStorage } from './EventStorage'
import { AppStorage } from './AppStorage'

class LocalStorage {
  storage() {
    return chrome.storage
  }

  clear() {
    return new Promise((resolve, reject) => {
      this.storage().local.clear(function () {
        const error = chrome.runtime.lastError;
        if (error) {
          resolve(false)
        } else {
          resolve(true)
        }
      })
    })
  }

  /**
   * Read value from local storage
   * @param key
   */
  async get(key: string) {
    return new Promise((resolve, reject) => {
      this.storage().local.get(key, function (result) {
        if (result[key] === undefined) {
          reject("");
        } else {
          resolve(result[key]);
        }
      });
    });
  };

  /**
   * Set value to config
   * @param key
   * @param value
   */
  set(key: string, value: any) {
    this.storage().local.set({[key]: value})
  }

  /**
   * Push value to the specified group
   * @param group
   * @param key
   * @param value
   */
  push(group: string, data: any, tabId?: any, refreshToolbar?: boolean, refreshSerp?: boolean, tabUrl?: string) {
    const event = new EventStorage()
    const that = this
    this.storage().local.get(group, function (result) {
      that.storage().local.set({[group]: {...result[group], ...data}}).then((res) => {
        // When value is set we need to send refresh events for on page elements
        const app = new AppStorage()
        if (refreshToolbar) {
          event.sendTabMessage(tabId,
            { type: event.SOURCE_CONTENT, from: event.SOURCE_EXTENSION, message: "show." + app.SETTING_TOOLBAR })
          event.sendTabStatusData(tabId, event.SOURCE_EXTENSION, tabUrl, data?.token)
        }
        if (refreshSerp) {
          event.sendTabMessage(tabId,
            event.buildMessage(event.SOURCE_CONTENT, event.SOURCE_EXTENSION, 'refresh.serp', {})
          )
        }
      }, (err) => {
        console.log('Error LS push: ', err)
      })
    });
  }
}

export {LocalStorage}
