interface ProfileInterface {
  engine: string | undefined
  country: string | undefined
  region: string | undefined
  city?: string | undefined
  name: string
}

class AppStorageProfile {
  public SETTING_PROFILE = 'profile'

  /**
   * Save or get profiles from local storage
   * @param profiles
   */
  public profiles(profiles: Array<ProfileInterface> | null = null): Array<ProfileInterface> {
    if (profiles) {
      localStorage.setItem(this.SETTING_PROFILE, JSON.stringify(profiles))
      return []
    } else {
      const data = localStorage.getItem(this.SETTING_PROFILE);
      if (data) {
        const items = JSON.parse(data)
        if (items) {
          return items
        } else {
          return []
        }
      } else {
        return []
      }
    }
  }

  /**
   * Add new profile
   * @param profile
   */
  public addProfile(profile: ProfileInterface) {
    const profiles = this.profiles()
    profiles.push(profile)
    this.profiles(profiles)
    return profiles.length
  }

  /**
   * Edit profile
   * @param index
   * @param profile
   */
  public editProfile(index: number, profile: ProfileInterface) {
    const profiles = this.profiles()
    if (profiles[index]) {
      profiles[index] = profile
      this.profiles(profiles)
      return true
    } else {
      return false
    }
  }

  /**
   * Get profile by index
   * @param index
   */
  public getProfile(index: number): ProfileInterface | undefined {
    const profiles = this.profiles()
    if (profiles[index]) {
      return profiles[index]
    }
  }

  /**
   * Delete profile
   * @param index
   */
  public deleteProfile(index: number) {
    const profiles = this.profiles()
    if (profiles[index]) {
      profiles.splice(index, 1)
      this.profiles(profiles)
      return true
    } else {
      return false
    }
  }
}

export { AppStorageProfile }
export type { ProfileInterface }

