import { v4 as uuidv4 } from 'uuid';
import fetchAdapter from '@vespaiach/axios-fetch-adapter'
import { MetaStorage } from '../helpers/MetaStorage'
import { AppStorage } from '../helpers/AppStorage'
import { LocalStorage } from '../helpers/LocalStorage'

const axios = require('axios')

/**
 * SERP Results Overlay: https://github.com/seomoz/app-api/blob/main/unified-api-documentation/review/MozbarPageOverviewFetchMultipleAction.md
 * Page Overview: https://github.com/seomoz/app-api/blob/main/unified-api-documentation/review/MozbarPageDetailFetchAction.md
 * Page Grader Report: https://github.com/seomoz/app-api/blob/main/unified-api-documentation/review/MozbarPageKeywordReportFetchAction.md
 * Ranking Keywords Report: https://github.com/seomoz/app-api/blob/main/unified-api-documentation/review/MozbarPageRankingKeywordListAction.md
 */
enum ApiServiceV2_Scope {
  Domain = 'domain',
  Subdomain = 'subdomain',
  Url = 'url'
}

class ApiServiceV2 {
  private endpoint: string = 'https://api.moz.com/jsonrpc'
  private endpoint_dev: string = 'https://development.api.moz.com'
  private token: string | undefined = ''
  private _error: Error | undefined

  /**
   * Base constructor
   * @param token
   */
  constructor (token?: string) {
    if (token) this.token = token
  }

  get error (): Error | undefined {
    return this._error
  }

  /**
   * Set token
   * @param token
   */
  setToken(token: string | undefined) {
    this.token = token
  }

  /**
   * Get current user's token
   */
  getToken() {
    return this.token
  }

  /**
   * Make sure provided URL is valid
   * @param url
   */
  getUrl(url: string) {
    const urlRegex = new RegExp(
      "^" +
      // protocol identifier (edited from original to be optional)
      "(?:(?:https?|ftp)://)?" +
      "(?:" +
      // IP address exclusion
      // private & local networks
      "(?!(?:10|127)(?:\\.\\d{1,3}){3})" +
      "(?!(?:169\\.254|192\\.168)(?:\\.\\d{1,3}){2})" +
      "(?!172\\.(?:1[6-9]|2\\d|3[0-1])(?:\\.\\d{1,3}){2})" +
      // IP address dotted notation octets
      // excludes loopback network 0.0.0.0
      // excludes reserved space >= 224.0.0.0
      // excludes network & broacast addresses
      // (first & last IP address of each class)
      "(?:[1-9]\\d?|1\\d\\d|2[01]\\d|22[0-3])" +
      "(?:\\.(?:1?\\d{1,2}|2[0-4]\\d|25[0-5])){2}" +
      "(?:\\.(?:[1-9]\\d?|1\\d\\d|2[0-4]\\d|25[0-4]))" +
      "|" +
      // host name
      "(?:(?:[a-z\\u00a1-\\uffff0-9]-*)*[a-z\\u00a1-\\uffff0-9]+)" +
      // domain name
      "(?:\\.(?:[a-z\\u00a1-\\uffff0-9]-*)*[a-z\\u00a1-\\uffff0-9]+)*" +
      // TLD identifier
      "(?:\\.(?:[a-z\\u00a1-\\uffff]{2,}))" +
      ")" +
      // port number
      "(?::\\d{2,5})?" +
      // resource path
      "(?:/?\\S*)?" +
      "$",
      "i"
    )
    if (urlRegex.test(url))
      return url
    else
      return ""
  }

  /**
   * Get request data as a Promise
   * @param url
   * @param body
   */
  async fetch_async(url: string, body?: object) {
    interface Headers {
      "Content-Type": string,
      "x-moz-token"?: string
    }
    const headers: Headers = {
      'Content-Type': 'application/json',
      'x-moz-token': this.getToken(),
    }
    return await axios.post(url, body, {
      headers: headers,
      withCredentials: true,
      adapter: fetchAdapter
    })
  }

  /**
   * User login
   * @param target
   */
  async login (user: string | undefined, password: string | undefined) {
    const query = {
      "jsonrpc": "2.0",
      "id": uuidv4(),
      "method": "user.login",
      "params": {
        "data": {
          "email": user,
          "password": password
        }
      }
    }
    return this.fetch_async(this.endpoint, query)
  }

  /**
   * Create base query
   * @param data
   */
  base (type: string, token: string, data: any): any {
    return {
      "jsonrpc": "2.0",
      "id": uuidv4(),
      "method": type,
      "params": {
        "auth": {
          "session_id": token
        },
        "data": data
      }
    }
  }

  /**
   * Get session status based on the token
   */
  async status () {
    const token = this.getToken()
    if (token) {
      const query = this.base("session.lookup", token, {
        "id": token
      })
      return this.fetch_async(this.endpoint, query)
    } else {
      return {}
    }
  }

  async cache (key: string, cacheLifeTime = 0) {
    return new Promise((resolve, reject) => {
      const ls = new LocalStorage()
      ls.storage().local.get(key, (result: any) => {
        const meta = new MetaStorage()
        const cacheLife = cacheLifeTime ? cacheLifeTime : meta.cacheLifetime
        const current = new Date().getTime() / 1000
        if (result[key] && result[key].created + cacheLife >= current) {
          resolve(result[key])
        } else {
          resolve(undefined)
        }
      })
    })
  }

  /**
   * Validate URL
   * @param url
   */
  validateUrl (url: string): boolean {
    const url_hndl = new URL(url)
    if (url_hndl.protocol=='http:' || url_hndl.protocol=='https:')
      return true
    else
      return false
  }

  /**
   * Check if quota is available to do a call
   * In case no quota information is available do quote request
   */
  async validateQuota(type: string = '') {
    const ls = new LocalStorage()
    const app = new AppStorage()

    const requestQuota = async () => {
      try {
        const res = await this.quota()
        app.setQuota(res?.data?.result?.quota)
        ls.set('quota', res?.data?.result?.quota)
        return res?.data?.result?.quota
      }
      catch(error1) {
        return null
      }
    }

    const current = new Date().getTime() / 1000
    let quota: any
    if (type === 'keyword') {
      try {
        quota = await ls.get('quota_keyword')
      }
      catch(error) {
        quota = await requestQuota()
      }
    } else {
      try {
        quota = await ls.get('quota')
      }
      catch(error) {
        quota = await requestQuota()
      }
    }
    if (
      quota && quota.used && quota.allotted
      && quota.used >= quota.allotted && quota.period_reset>current
    ) {
      return false
    }
    return true
  }

  /**
   * Page overview
   * Page Overview: https://github.com/seomoz/app-api/blob/main/unified-api-documentation/review/MozbarPageDetailFetchAction.md
   */
  async quota () {
    const meta = new MetaStorage()
    const token = this.getToken()

    if (token) {
      const type = "quota.lookup"
      return this.fetch_async(this.endpoint, this.base(type, token, {
        "path": "search.limits.mozbar.rows"
      }))
    } else {
      return new Promise((resolve, reject) => {
        reject(meta.queryGeneralError)
      })
    }
  }

  /**
   * Page overview
   * Page Overview: https://github.com/seomoz/app-api/blob/main/unified-api-documentation/review/MozbarPageDetailFetchAction.md
   */
  async overview (url: string, scope?: string, locale?: string) {
    const meta = new MetaStorage()
    const token = this.getToken()
    if (!scope) scope = ApiServiceV2_Scope.Subdomain
    if (!locale) locale = 'en-US'

    if (token && url && this.getUrl(url)) {
      const type = "mozbar.page.detail.fetch"
      return this.fetch_async(this.endpoint, this.base(type, token, {
        "target_query": {
          "query": url,
          "scope": scope,
          "locale": locale
        }
      }))
    } else {
      return new Promise((resolve, reject) => {
        reject(meta.queryGeneralError)
      })
    }
  }

  /**
   * Page overview
   * Page Overview: https://github.com/seomoz/app-api/blob/main/unified-api-documentation/review/MozbarPageDetailFetchAction.md
   */
  async overview_cache (url: string | undefined, scope?: string, locale?: string, single_run: boolean = false) {
    console.log('URL: ', url)

    const ls = new LocalStorage()
    const meta = new MetaStorage()
    const app = new AppStorage()
    const token = this.getToken()
    if (!scope) scope = ApiServiceV2_Scope.Subdomain
    if (!locale) locale = 'en-US'

    if (token && url && this.getUrl(url)) {
      let url_proc = new URL(url).href
      console.log('URL overview: ', url_proc)
      const type = "mozbar.page.detail.fetch"
      const key = 'url_' + type + '_' + btoa(url_proc ? url_proc : '') + '_' + scope + '_' + locale
      const cache = await this.cache(key)
      if (cache) {
        return new Promise((resolve, reject) => {
          resolve(cache)
        })
      } else {
        const quotaAvailable = await this.validateQuota()
        return new Promise((resolve, reject) => {
          if (quotaAvailable) {
            this.fetch_async(this.endpoint, this.base(type, token, {
              "target_query": {
                "query": url_proc,
                "scope": scope,
                "locale": locale
              }
            })).then((res) => {
              const result = res?.data?.result?.page_detail || ''
              app.setQuota(res?.data?.result?.quota)
              ls.set('quota', res?.data?.result?.quota)
              result.created = new Date().getTime() / 1000
              ls.set(key, result)
              resolve(result)
            }, (err) => {
              // Re-request data for the domain if no data is found for the specified URL
              if (single_run) {
                reject(meta.queryGeneralErrorPrefix + err.response?.data?.error?.message)
              } else {
                const url_hndl = new URL(url)
                const url_proc = url_hndl.protocol + url_hndl.host
                if (url != url_proc && this.validateUrl(url)) {
                  // Handle redirects
                  fetch(url_proc)
                    .then(response => {
                      if (response.redirected) {
                        this.overview_cache(response.url, scope, locale, true).then((res) => {
                          resolve(res)
                        }, (err) => {
                          reject(err)
                        })
                      }
                      return response.text();
                    })
                    .catch(error => {
                      reject(err)
                    })
                } else {
                  reject(meta.queryGeneralErrorPrefix + err.response?.data?.error?.message)
                }
              }
            })
          } else {
            reject("")
          }
        })
      }
    } else {
      return new Promise((resolve, reject) => {
        reject("")
      })
    }
  }

  /**
   * Page grader
   * Page Grader Report: https://github.com/seomoz/app-api/blob/main/unified-api-documentation/review/MozbarPageKeywordReportFetchAction.md
   */
  async grader (keyword: string, url: string, scope?: string, locale?: string) {
    const meta = new MetaStorage()
    const token = this.getToken()
    if (!scope) scope = ApiServiceV2_Scope.Subdomain
    if (!locale) locale = 'en-US'

    if (token && url && this.getUrl(url)) {
      return this.fetch_async(this.endpoint, this.base("mozbar.page.keyword.report.fetch", token, {
        "keyword": keyword,
        "target_query": {
          "query": url,
          "scope": scope,
          "locale": locale
        }
      }))
    } else {
      return new Promise((resolve, reject) => {
        reject(meta.queryGeneralError)
      })
    }
  }

  /**
   * Page grader
   * Page Grader Report: https://github.com/seomoz/app-api/blob/main/unified-api-documentation/review/MozbarPageKeywordReportFetchAction.md
   */
  async grader_cache (keyword: string, url: string, scope?: string, locale?: string) {
    const meta = new MetaStorage()
    const token = this.getToken()
    if (!scope) scope = ApiServiceV2_Scope.Subdomain
    if (!locale) locale = 'en-US'

    if (token && url && this.getUrl(url)) {
      const type = "mozbar.page.keyword.report.fetch"
      const key = 'url_' + type + '_' + keyword + '_' + btoa(url ? url : '') + '_' + scope + '_' + locale
      const cache = await this.cache(key)
      if (cache) {
        return new Promise((resolve, reject) => {
          resolve(cache)
        })
      } else {
        const quotaAvailable = await this.validateQuota()
        return new Promise((resolve, reject) => {
          if (quotaAvailable) {
            this.fetch_async(this.endpoint, this.base(type, token, {
              "keyword": keyword,
              "target_query": {
                "query": url,
                "scope": scope,
                "locale": locale
              }
            })).then((res) => {
              const ls = new LocalStorage()
              const app = new AppStorage()
              const result = res?.data?.result?.keyword_report || ''
              app.setQuota(res?.data?.result?.quota)
              ls.set('quota', res?.data?.result?.quota)
              result.created = new Date().getTime() / 1000
              ls.set(key, result)
              resolve(result)
            }, (err) => {
              reject(meta.queryGeneralErrorPrefix + err.response?.data?.error?.message)
            })
          } else {
            reject("")
          }
        })
      }
    } else {
      return new Promise((resolve, reject) => {
        reject("")
      })
    }
  }

  /**
   * Keywords
   * Ranking Keywords Report: https://github.com/seomoz/app-api/blob/main/unified-api-documentation/review/MozbarPageRankingKeywordListAction.md
   */
  async keywords (url: string, scope?: string, locale?: string) {
    const meta = new MetaStorage()
    const token = this.getToken()
    if (!scope) scope = ApiServiceV2_Scope.Domain
    if (!locale) locale = 'en-US'

    if (token && url && this.getUrl(url)) {
      return this.fetch_async(this.endpoint, this.base("mozbar.page.ranking.keyword.list", token, {
        "target_query": {
          "query": url,
          "scope": ApiServiceV2_Scope.Subdomain,
          "locale": locale
        }
      }))
    } else {
      return new Promise((resolve, reject) => {
        reject(meta.queryGeneralError)
      })
    }
  }

  /**
   * Keywords
   * Ranking Keywords Report: https://github.com/seomoz/app-api/blob/main/unified-api-documentation/review/MozbarPageRankingKeywordListAction.md
   */
  async keywords_cache (url: string, scope?: string, locale?: string) {
    const meta = new MetaStorage()
    const token = this.getToken()
    if (!scope) scope = ApiServiceV2_Scope.Subdomain
    if (!locale) locale = 'en-US'

    if (token && url && this.getUrl(url)) {
      const type = "mozbar.page.ranking.keyword.list"
      const key = 'url_' + type + '_' + btoa(url ? url : '') + '_' + scope + '_' + locale
      const cache = await this.cache(key)
      if (cache) {
        return new Promise((resolve, reject) => {
          resolve(cache)
        })
      } else {
        const quotaAvailable = await this.validateQuota('keyword')
        return new Promise((resolve, reject) => {
          if (quotaAvailable) {
            this.fetch_async(this.endpoint, this.base(type, token, {
              "target_query": {
                "query": url,
                "scope": ApiServiceV2_Scope.Subdomain,
                "locale": locale
              },
            })).then((res) => {
              const ls = new LocalStorage()
              const app = new AppStorage()
              const result = res?.data?.result?.ranking_keywords || ''
              app.setQuota(res?.data?.result?.quota, 'keyword')
              ls.set('quota_keyword', res?.data?.result?.quota)
              result.created = new Date().getTime() / 1000
              ls.set(key, result)
              resolve(result)
            }, (err) => {
              reject(meta.queryGeneralErrorPrefix + err.response?.data?.error?.message)
            })
          } else {
            reject("")
          }
        })
      }
    } else {
      return new Promise((resolve, reject) => {
        reject("")
      })
    }
  }

  /**
   * SERP results
   * SERP Results Overlay: https://github.com/seomoz/app-api/blob/main/unified-api-documentation/review/MozbarPageOverviewFetchMultipleAction.md
   */
  async serp (url: string[], scope?: string, locale?: string) {
    const meta = new MetaStorage()
    const token = this.getToken()
    if (!scope) scope = ApiServiceV2_Scope.Subdomain
    if (!locale) locale = 'en-US'

    if (token && url) {
      const targets: any[] = []
      url.forEach((item) => {
        targets.push({
          "query": item,
          "scope": scope,
          "locale": locale
        })
      })
      if (targets.length) {
        return this.fetch_async(this.endpoint, this.base("mozbar.page.overview.fetch.multiple", token, {
          "target_queries": targets
        }))
      } else {
        return new Promise((resolve, reject) => {
          reject(meta.queryGeneralError)
        })
      }
    } else {
      return new Promise((resolve, reject) => {
        reject(meta.queryGeneralError)
      })
    }
  }
}

export {ApiServiceV2, ApiServiceV2_Scope}
