import { runtime, storage, tabs } from 'webextension-polyfill'
import { EventStorage } from '../helpers/EventStorage'
import { TabStorage } from '../helpers/TabStorage'
import { ApiServiceV2, ApiServiceV2_Scope } from '../api/api_v2'
import { MetaStorage } from '../helpers/MetaStorage'
import { LocalStorage } from '../helpers/LocalStorage'
import RequestFilter = chrome.webRequest.RequestFilter

type Message = {
  from: string
  to: string
  action: string
}

const ls = new LocalStorage()
const event = new EventStorage()
const tabsApi = event.tabs()
const actionApi = event.action()

const readLocalStorage = (key: string) => {
  return ls.get(key)
};

export async function init() {
  await storage.local.clear()
}

runtime.onInstalled.addListener(() => {
  init().then(() => {
  })
})

const filters: RequestFilter = ({urls: ["<all_urls>"], types: ["main_frame"]})

const tabsData: any = {}
const prefix = new TabStorage().TAB_PREFIX

/**
 * Handle page statuses and redirects
 */
chrome.webRequest.onBeforeRedirect.addListener((details) => {
  const tabId = details.tabId
  if (tabsData[prefix + tabId] && tabsData[prefix + tabId][tabsData[prefix + tabId].length-1]) {
    tabsData[prefix + tabId][tabsData[prefix + tabId].length-1].redirect = true
  }
}, filters)
chrome.webRequest.onBeforeRequest.addListener((details) => {
  const tabId = details.tabId
  if (tabsData[prefix + tabId]
    && tabsData[prefix + tabId][tabsData[prefix + tabId].length-1]
    && tabsData[prefix + tabId][tabsData[prefix + tabId].length-1].redirect
  )
    return
  tabsData[prefix + tabId] = []
}, filters)
chrome.webRequest.onHeadersReceived.addListener( (details) => {
  const tabId = details.tabId
  if (tabsData[prefix + tabId]) {
    tabsData[prefix + tabId].push({
      statusCode: details.statusCode,
      statusLine: details.statusLine,
      url: details.url
    })
    ls.storage().local.set({ tabscache: tabsData })
  }
}, filters)

/**
 * Update tab data
 */
const statusTabUpdate = () => {
  // Send message to content script to update data
  // Get current config for extension
  readLocalStorage('config').then((res: any) => {
    // Send message to content script to update data
    if (tabsApi) {
      tabsApi.query({
        active: true,
        currentWindow: true
      }, function (tabs) {
        const [tab] = tabs
        if (tab && tab.id && tab.url) {
          event.sendTabStatusData(tab.id, event.SOURCE_BACKGROUND, tab.url, res?.token)
        }
      })
    }
  }, (err) => {
    console.log('Background config 3 err: ', err)
  })
}

/**
 * Set default extension icon
 */
const setDefaultIcon = () => {
  const manifest = runtime.getManifest()
  if ('action' in manifest && actionApi) {
    actionApi.setIcon({ path: manifest?.action?.default_icon })
  }
}

/**
 * Update extension property in the local storage
 * @param property
 * @param value
 */
const updateBackendProperty = (property: string, value: any) => {
  ls.push('config', {[property]: value})
}

/**
 * Method to be executed when tab goes active
 * @param tabId
 */
const refreshTabData = (tabId: number) => {
  const meta = new MetaStorage()

  // Get current config for extension
  readLocalStorage('config').then((config: any) => {
    // Try to read cookie data in case user is not signed in
    if (!config?.token) {
      const cookiesApi = event.cookies()
      if (cookiesApi) {
        cookiesApi.get({ "url": meta.cookie_web, "name": meta.cookie_name }, function (cookie) {
          if (cookie?.value) {
            const token = cookie?.value
            const data = { session: token }
            ls.storage().local.set(data)
          }
        })
      }
    }

    // Send message to content script to update data
    if (tabsApi) {
      tabsApi.query({
        active: true,
        currentWindow: true
      }, function (tabs) {
        const [tab] = tabs
        if (tab && tab.id && tab.url) {
          event.sendTabMessage(tab.id, event.buildMessage(event.SOURCE_CONTENT, event.SOURCE_BACKGROUND, 'config', config))
        }
      })
    }

    // Update tab status data
    statusTabUpdate()
  }, (err) => {
    console.log('No config data found. ')
  })
}

if (tabsApi) {
  tabsApi.onUpdated.addListener(function (tabId, changeInfo, tab) {
    if (changeInfo.status == 'complete' && tab.active) {
      refreshTabData(tabId)
    }
  })
  /**
   * Switch tab event
   * Need to reactivate toolbar and SERP results
   */
  tabsApi.onActivated.addListener((activeInfo) => {
    refreshTabData(activeInfo.tabId)
  });
}

// Setting a toolbar badge text
runtime.onMessage.addListener((request, sender, sendResponse) => {
  if (request.type === 'background') {
    switch (request.message) {
      /**
       * Set extension icon
       */
      case 'set-icon':
        if (!request.data) {
          setDefaultIcon()
        } else {
          try {
            const convert = Object.keys(request.data).map(function (key) {
              return Number(request.data[key]);
            })
            const input = Uint8ClampedArray.from(convert)
            const data = new ImageData(input, 15, 15)
            if (actionApi) {
              actionApi.setIcon({ imageData: data }).then((res) => {
              }, (err) => {
                setDefaultIcon()
              })
            }
          } catch (err) {
            setDefaultIcon()
          }
        }
        break

      /**
       * Save page load time
       */
      case 'pageinfo-time':
        const prefix = new TabStorage().TAB_PREFIX
        const tabId = sender.tab?.id
        const time = request.time
        const timing = request.timing

        // This cache stores page load time for each tab, so they don't interfere
        ls.storage().local.get('cache').then(data => {
          if (!data.cache) data.cache = {}
          data.cache[prefix + tabId] = { time: time, timing: timing }
          ls.storage().local.set(data)
        })

        // cache eviction
        if (tabsApi) {
          tabsApi.onRemoved.addListener(tabId => {
            ls.storage().local.get('cache').then(data => {
              if (data.cache) delete data.cache[prefix + tabId]
              ls.storage().local.set(data)
            })
          })
        }
        break

      /**
       * Open custom link in browser in the new tab
       */
      case 'openlink':
        if (tabsApi) {
          tabsApi.create({ url: request.data })
        }
        break

      /**
       * Save config
       */
      case 'config':
        if (request.from === event.SOURCE_EXTENSION) {
          // save storage
          ls.storage().local.set({config: request.data})
        } else if (request.from === event.SOURCE_CONTENT) {
          // send storage to content
          readLocalStorage('config').then((res) => {
            // console.log('Background config: ', res)
          }, (err) => {
            // console.log('Background config err: ', err)
          })
        }
        break

      /**
       * Get page status details
       */
      case 'status-request':
        statusTabUpdate()
        break

      /**
       * Get page status details
       */
      case 'serp':
      case 'serp-export':
        // Send message to content script to update serp data
        // Get current serp data for the page
        readLocalStorage('config').then((res: any) => {
          if (tabsApi) {
            tabsApi.query({
              active: true,
              currentWindow: true
            }, function (tabs) {
              const [tab] = tabs
              if (tab && tab.id && tab.url) {
                const api = new ApiServiceV2()
                const event = new EventStorage()
                api.setToken(res?.token)
                const key = 'serp_' + '_' + btoa(request.data.links.join())
                api.cache(key, (new MetaStorage()).cacheLifetimeSerp).then((cache) => {
                  if (cache) {
                    event.sendTabMessage(tab.id, event.buildMessage(event.SOURCE_CONTENT, event.SOURCE_BACKGROUND, request.message, cache))
                  } else {
                    api.serp(request.data.links, ApiServiceV2_Scope.Url).then((res) => {
                      const result = {
                        created: new Date().getTime() / 1000,
                        data: res.data?.result?.results_by_target
                      }
                      event.sendTabMessage(tab.id, event.buildMessage(event.SOURCE_CONTENT, event.SOURCE_BACKGROUND, request.message, result))
                      ls.set(key, result)
                    })
                  }
                })
                // }, (err) => {
                //   console.log('Background api serp err: ', err)
                // })
              }
            })
          }
        }, (err) => {
          console.log('Background config err: ', err)
        })
        break

      /**
       * Save property to be updated on extension start
       */
      case 'property':
        readLocalStorage('update').then((res: any) => {
          res[request.data.property] = request.data.value
          ls.storage().local.set({update: res})
        }, (err) => {
          const res = [];
          res[request.data.property] = request.data.value
          ls.storage().local.set({update: res})
        })
        break
    }
  }
})