  /**
   * Format number with commas and K and M if required
   * @param number
   */
  public numberFormat(number: number | undefined | null, needK: boolean = false): string {
    if (number && number>1000000000) needK = true
    if (needK && number) {
      if (number / 1000000 >= 1) {
        const item = (number / 1000000).toFixed(1).replace(/\B(?=(\d{3})+(?!\d))/g, ",")
        return item + 'M'
      } else if (number / 1000 >= 1) {
        const item = (number / 1000).toFixed(1).replace(/\B(?=(\d{3})+(?!\d))/g, ",")
        return item + 'K'
      } else {
        return number.toString().replace(/\B(?=(\d{3})+(?!\d))/g, ",")
      }
    } else if (number) {
      return number.toString().replace(/\B(?=(\d{3})+(?!\d))/g, ",")
    } else {
      return '-'
    }
  }

  /**
   * Google cache URL
   * @param url
   */
  public buildGoogleCacheUrl(url: string | undefined): string {
    if (url)
      return 'http://www.google.com/search?q=cache%3a' + url
    else
      return 'http://www.google.com/search?q=cache%3a'
  }

  /**
   * Open link
   * @param url
   */
  public openContentLink(url: string) {
    if (url) {
      // window.location.href = url
      window.open(url, "_blank")
    }
  }

  /**
   * Build link to open metrics on the moz website
   * @param url
   * @param target
   * @param locale
   */
  public buildMetricsLink(url: string | undefined, target?: string, locale?: string) {
    if (!locale) locale = 'en-us'
    if (!target) target = 'page'
    if (!url) return 'https://analytics.moz.com/pro/link-explorer/overview'
    const metaStorage = new MetaStorage()
    url = metaStorage.getUrlNoQuery(url)
    return 'https://analytics.moz.com/pro/link-explorer/overview?site=' + url + '&target=' + target + '&src=mb'
  }

  /**
   * Get SE logo in base64
   * @param type
   */
  getSEImage(type: string): string {
    switch(type) {
      case 'google':
        return 'data:image/png;base64,'
      case 'bing':
        return 'data:image/png;base64,'
      case 'yahoo':
        return 'data:image/png;base64,'
    }
    return ''
  }

  /**
   * Export keywords
   * @param keywords
   */
  public exportCSV(data: any, headers: string, filename: string) {
    const convertToCSV = (data: any) => {
      const array = typeof data !== 'object' ? JSON.parse(data) : data
      let str = headers + '\r\n'
      for (let i = 0; i < array.length; i++) {
        let line = ''
        for (let index in array[i]) {
          if (line !== '') line += ','
          // Add quotes in case value contains comma
          if (array[i][index]) {
            line += array[i][index].toString().search(',') !== -1 ?
              '"' + array[i][index] + '"' : array[i][index]
          }
        }
        str += line + '\r\n'
      }
      return str
    }

    const downloadCSV = (data: any, filename: string) => {
      const csvData = new Blob([convertToCSV(data)], { type: 'text/csv' })
      const csvURL = URL.createObjectURL(csvData)
      const link = document.createElement('a')
      link.href = csvURL
      link.download = `${filename}.csv`
      document.body.appendChild(link)
      link.click()
      document.body.removeChild(link)
    }

    downloadCSV(data, filename)
  }

  /**
   * Check if URL belongs to block list
   * @param url
   * @param list
   */
  public matchBlockList(url: string, list: string) {
    let match = false
    list?.split("\n").forEach((line: string) => {
      // Make sure line is not empty
      if (line.length>0) {
        const re = new RegExp(line, 'g')
        if (url.search(re) >= 0) match = true
      }
    })
    return match
  }

  /**
   * Get only top level domain from provided URL OR subdomain as is
   * @param url
   */
  public getDomain(url: string, isSubdomain: boolean = false, excludeProtocol: boolean = false) {
    const toURL = (value: unknown) => {
      if (value instanceof URL) {
        return value
      }
      if (typeof value !== 'string' || !value) {
        return null
      }
      try {
        const url = new URL(value);
        return url.hostname ? url : null;
      } catch (error) {
        return null
      }
    }

    const item = toURL(url);
    if (!item) return null

    if (isSubdomain) {
      return (excludeProtocol ? '' : (item.protocol + '//')) + item.host
    }

    const hostnameParts = item.hostname.split('.');
    if (hostnameParts.length <= 2) {
      return (excludeProtocol ? '' : (item.protocol + '//')) + item.hostname;
    }
    const prefixes = ['com', 'co', 'org', 'net', 'gov', 'edu']
    const potentialTwoPartTLD = `${hostnameParts[hostnameParts.length - 2]}.${hostnameParts[hostnameParts.length - 1]}`
    return prefixes.includes(hostnameParts[hostnameParts.length - 2])
      ? (excludeProtocol ? '' : (item.protocol + '//')) + `${hostnameParts[hostnameParts.length - 3]}.${potentialTwoPartTLD}`
      : (excludeProtocol ? '' : (item.protocol + '//')) + hostnameParts.slice(-2).join('.')
  }

  /**
   * Get URL with no query string
   * @param url
   */
  public getUrlNoQuery (url: string | undefined) {
    if (url) {
      const data = new URL(url)
      return data.protocol + '//' + data.hostname + '' + data.pathname
    } else {
      return url
    }
  }

  /**
   * Get quota end date string from timestamp
   * @param quotaTimestamp
   */
  public getQuotaEndDate(quotaTimestamp: number) {
    const fullDate = new Date(quotaTimestamp * 1000)
    return (fullDate.getMonth()+1) + '/' + fullDate.getDate()
  }

  /**
   * Build quota message based on parameters
   * @param used
   * @param allotted
   * @param timestamp
   */
  public buildQuotaMessage(used: number, allotted: number, timestamp: number, is_pro = false, is_toolbar = false) {
    const date = this.getQuotaEndDate(timestamp)
    if (used < allotted) {
      if (is_toolbar) {
        if (date)
          return [(allotted - used) + " of " + allotted + " queries\navailable until " + date, ""]
        else
          return [(allotted - used) + " of " + allotted + " queries\navailable this month", ""]
      } else {
        if (date)
          return [(allotted - used) + " of " + allotted + " queries available until " + date, ""]
        else
          return [(allotted - used) + " of " + allotted + " queries available this month", ""]
      }
    } else {
      if (is_toolbar) {
        return ["Your monthly query limit\nhas been reached until " + date, ""]
      } else {
        if (is_pro) {
          return ["Your monthly queries limit has been reached until " + date + ". " +
          "Contact a Moz support agent for more information, or wait until next month for your quota to be reset.", "#FF7F75"]
        } else {
          return ["Your monthly queries limit has been reached until " + date + ". " +
          "You can upgrade to Moz Pro to get more or wait until next month for your quota to be reset.", "#FF7F75"]
        }
      }
    }
  }
