import { storage } from 'webextension-polyfill'

class TabStorage {
  public TAB_PREFIX = 'pageinfo-tab-'

  /**
   * Get tab load time
   * @param tabId
   * @param callback
   */
  getPageLoadTime(tabId: number, callback: any) {
    storage.local.get('cache').then(data => {
      const tabName = this.TAB_PREFIX + tabId
      if (data.cache && data.cache[tabName]) {
        callback(data.cache[tabName].time)
      }
    });
  }

  /**
   * Get tab status line
   * @param tabId
   * @param callback
   */
  getStatusLine(tabId: number, callback: any) {
    storage.local.get('cache').then(data => {
      const tabName = this.TAB_PREFIX + tabId
      if (data.cache && data.cache[tabName]) {
        callback('HTTP/1.1 ' + data.cache[tabName].timing.responseStatus)
      }
    });
  }

  /**
   * Get tab status line
   * @param tabId
   * @param callback
   */
  getTabsData(tabId: number, callback: any) {
    storage.local.get('tabscache').then(data => {
      const tabName = this.TAB_PREFIX + tabId
      if (data.tabscache && data.tabscache[tabName]) {
        let items: any = []
        data.tabscache[tabName].forEach((item: any) => {
          items.push(item.statusLine + " -> " + item.url)
        })
        callback(items)
      }
    });
  }
}

export {TabStorage}
